1	// OKKI AI Classification Engine v3
2	// Key: <30d silence = active stage + silence sub-state; 30d+ = 搁置 terminal
3	
4	const fs = require('fs');
5	const s2 = JSON.parse(fs.readFileSync('./data/s2_ai_input.json', 'utf8'));
6	
7	function classify(c) {
8	  const totalMsgs = c.totalMsgs || 0;
9	  const customerMsgs = c.customerMsgs || 0;
10	  const ourMsgs = c.ourMsgs || 0;
11	  const lastCust = c.lastCustomerMsgDays != null ? c.lastCustomerMsgDays : 999;
12	  const dir = c.direction;
13	  const order = c.order;
14	  const snippet = c.snippet || [];
15	  const snippetText = snippet.join(' ');
16	
17	  let stage = '需求探索';
18	  let priority = 'idle';
19	  let reason = '';
20	
21	  // Content detectors
22	  const hasQuote = /报价|quote|price|\$[0-9]+\b|offer\b|\bPI\b|proforma|invoice|unit price|成交价|总价|total.{0,20}price|价格.{0,10}\$|\$[0-9]+\.[0-9]+/i.test(snippetText);
23	  const hasNegotiation = /negotiate|商量|discount|MOQ|minimum|样品|sample|定制|custom\b|logo|brand|图案|pattern|design|customiz/i.test(snippetText);
24	  const hasPayment = /payment|付款|deposit|定金|paid|收款|confirm.{0,20}order|确认.{0,10}订单|pay now/i.test(snippetText);
25	  const hasShipping = /ship|tracking|物流|express|courier|delivery|收货|forwarder|transitaire|tracking.{0,10}number|运单|sent.{0,10}goods|enviado|expédié/i.test(snippetText);
26	  const hasReceived = /received|收到|arrived|arrivé|reçu|满意|satisf|happy|love.{0,5}it|great.{0,10}product|encantaron|merci beaucoup|already.*got|已经.*收到/i.test(snippetText);
27	  const hasComplaint = /(?:quality|product|order|shipment).{0,5}(?:problem|issue|defect|complaint)|wrong.{0,10}(?:product|item|size|color|order)|退款|退货|refund|not.{0,5}(?:good|right|what.{0,5}ordered|correct)|damaged|missing|defect/i.test(snippetText);
28	  const hasRFQ = /RFQ|rfq market/i.test(snippetText);
29	  const hasSupplierPromise = /(?:i will|i'll|我会|let me|please wait).{0,30}(?:send|check|reply|update|confirm|look into|get back|find|prepare|create|provide)/i.test(snippetText);
30	
31	  // === ORDER-BASED (highest priority) ===
32	  if (order && order.matched) {
33	    const st = order.status;
34	    if (st === '待收款') {
35	      stage = '待付款';
36	      if (lastCust <= 7) { priority = 'now'; reason = '有订单待收款，客户' + lastCust + '天前活跃'; }
37	      else if (lastCust <= 30) { priority = 'soon'; reason = '有订单待收款，静默' + lastCust + '天需催款'; }
38	      else { priority = 'idle'; reason = '有订单待收款但静默' + lastCust + '天'; }
39	      return { stage, priority, reason };
40	    }
41	    if (st === '待发货') {
42	      stage = '待发货';
43	      if (lastCust <= 14) { priority = 'soon'; reason = '订单待发货，静默' + lastCust + '天'; }
44	      else { priority = 'idle'; reason = '订单待发货，静默' + lastCust + '天'; }
45	      return { stage, priority, reason };
46	    }
47	    if (st === '已发货') {
48	      stage = '已发货/在途';
49	      if (lastCust <= 14) { priority = 'now'; reason = '在途需跟踪物流，静默' + lastCust + '天'; }
50	      else { priority = 'soon'; reason = '在途，静默' + lastCust + '天需跟踪到港'; }
51	      return { stage, priority, reason };
52	    }
53	    if (st === '交易成功') {
54	      if (lastCust <= 60) {
55	        stage = '已签收';
56	        priority = lastCust <= 30 ? 'soon' : 'idle';
57	        reason = '订单交易成功已签收，静默' + lastCust + '天';
58	      } else {
59	        stage = '搁置'; priority = 'idle';
60	        reason = '订单完成超60天，自然搁置';
61	      }
62	      return { stage, priority, reason };
63	    }
64	    if (st === '交易取消') {
65	      stage = '未成交'; priority = 'idle';
66	      reason = '订单已取消';
67	      return { stage, priority, reason };
68	    }
69	  }
70	
71	  // === CONTENT-BASED STAGE ===
72	  // Determine active stage from content
73	  // v3.1: added minimum thresholds to prevent stage inflation
74	  if (hasQuote && hasNegotiation && totalMsgs >= 6 && customerMsgs >= 2) {
75	    stage = '谈判中';
76	  } else if (hasQuote && totalMsgs >= 4) {
77	    stage = '报价已发';
78	  } else if (hasNegotiation && totalMsgs >= 6 && customerMsgs >= 2) {
79	    stage = '谈判中';
80	  } else if (hasShipping && hasReceived && order && order.matched) {
81	    stage = '已签收';
82	  } else if (hasShipping && !hasReceived) {
83	    stage = '已发货/在途';
84	  } else if (hasComplaint) {
85	    stage = '售后';
86	  } else if (hasPayment && order && order.matched) {
87	    stage = '待付款';
88	  } else if (hasRFQ) {
89	    stage = '报价已发';
90	    reason = 'RFQ报价客户';
91	  }
92	
93	  // === SILENCE → TERMINAL OVERRIDE ===
94	  // 30d+ silence → 搁置 (regardless of stage)
95	  if (lastCust > 90) {
96	    const from = stage;
97	    stage = '搁置';
98	    priority = 'idle';
99	    reason = '深度静默' + lastCust + '天（从' + from + '掉出）';
100	    return { stage, priority, reason };
101	  }
102	
103	  if (lastCust > 30) {
104	    const from = stage;
105	    // Exception: 已签收 has longer tolerance
106	    if (from === '已签收' && lastCust <= 90) {
107	      priority = 'idle';
108	      reason = '已签收，静默' + lastCust + '天';
109	      return { stage, priority, reason };
110	    }
111	    stage = '搁置';
112	    priority = 'idle';
113	    reason = '静默' + lastCust + '天（从' + from + '掉出）';
114	    return { stage, priority, reason };
115	  }
116	
117	  // === PRIORITY FOR ACTIVE STAGE (<30d silence) ===
118	  // Now: <3d silence or ball-in-our-court
119	  // Soon: 3-14d for quote/negotiation/shipping, 3-7d for exploration
120	  // Idle: 14-30d for most, 7-30d for simple exploration
121	
122	  if (lastCust <= 1) {
123	    priority = 'now';
124	  } else if (lastCust <= 3) {
125	    priority = 'now';  // 3天内客户有回应，必须马上跟进
126	  } else if (lastCust <= 7) {
127	    priority = 'soon';
128	  } else if (lastCust <= 14) {
129	    if (stage === '需求探索' && totalMsgs < 10) {
130	      priority = 'idle';
131	    } else {
132	      priority = 'soon';
133	    }
134	  } else {
135	    // 14-30d
136	    if (['报价已发', '谈判中', '已发货/在途', '待付款'].includes(stage)) {
137	      priority = 'soon';
138	    } else {
139	      priority = 'idle';
140	    }
141	  }
142	
143	  // Override: ball in our court
144	  if (dir === 'to_us' && lastCust <= 7) {
145	    priority = 'now';
146	  }
147	
148	  // Override: supplier made a promise but never delivered (≥14d silence)
149	  if (hasSupplierPromise && lastCust >= 14 && lastCust <= 60 && stage !== '搁置') {
150	    priority = 'now';
151	    reason = (reason || '') + '；我方有未兑现承诺';
152	  }
153	
154	  if (!reason) {
155	    const silLabel = lastCust <= 3 ? '活跃' : (lastCust <= 7 ? '短期沉默' : (lastCust <= 14 ? '中期沉默' : '长期沉默'));
156	    reason = stage + '中，' + silLabel + lastCust + '天';
157	  }
158	
159	  return { stage, priority, reason };
160	}
161	
162	function correctGrade(c, snippetText) {
163	  let grade = c.grade;
164	  let override = null;
165	
166	  // Phantom / non-customer accounts
167	  if (['Leon Scott Kennedy', 'Anne Shen', 'User name', '(未知)', 'd zm'].includes(c.name)) {
168	    return { grade: 'D', override: 'D' };
169	  }
170	
171	  // Personal use → downgrade
172	  if (/(?:uso personal|personal use|for myself|my baby|mon bébé|primipare)/i.test(snippetText) && c.totalMsgs < 50) {
173	    if (grade === 'A') return { grade: 'B', override: 'B' };
174	    if (grade === 'B') return { grade: 'C', override: 'C' };
175	  }
176	
177	  // Adult clothing mismatch → D (but NOT if they have existing orders)
178	  if (/(?:ropa de mujer|women.*cloth|adult.*cloth|period pant|seamless pant|femme.*adulte|pour femme)/i.test(snippetText)) {
179	    if (/(?:solo.*bebé|solo.*niño|only.*baby|only.*infant|only.*kid|fabricamos.*bebé|manufacture.*baby|only make.*baby)/i.test(snippetText)) {
180	      if (grade !== 'S' && !(c.order && c.order.matched)) {
181	        return { grade: 'D', override: 'D' };
182	      }
183	    }
184	  }
185	
186	  // Suspicious names → D (now covered by ghost list above; kept as safety net)
187	  if (c.name === 'User name' || c.name === '(未知)') {
188	    return { grade: 'D', override: 'D' };
189	  }
190	
191	  // Dead accounts: 1 customer message + 60d+ silence
192	  if (c.customerMsgs <= 1 && c.lastCustomerMsgDays > 60 && c.totalMsgs <= 5) {
193	    if (grade === 'A' || grade === 'B') return { grade: 'D', override: 'D' };
194	  }
195	
196	  return { grade, override };
197	}
198	
199	// Process
200	const results = [];
201	const stageDist = {};
202	const priorityDist = {};
203	const gradeDist = {};
204	let gradeCorrections = 0;
205	
206	s2.forEach(c => {
207	  const cls = classify(c);
208	  const snippetText = (c.snippet || []).join(' ');
209	  const gradeResult = correctGrade(c, snippetText);
210	  const finalGrade = gradeResult.grade;
211	
212	  const entry = {
213	    name: c.name,
214	    cid: c.cid,
215	    country: c.country,
216	    stage: cls.stage,
217	    grade: finalGrade,
218	    priority: cls.priority,
219	    actionHint: cls.reason,
220	    reason: cls.reason,
221	    confidence: 'high',
222	    actionPriority: cls.priority,
223	    stageLabel: cls.stage,
224	    actionStatus: cls.priority === 'now' ? '紧急' : (cls.priority === 'soon' ? '尽快处理' : '观察'),
225	    actionText: cls.reason
226	  };
227	  if (gradeResult.override) {
228	    entry.gradeOverride = gradeResult.override;
229	    gradeCorrections++;
230	  }
231	
232	  results.push(entry);
233	  stageDist[cls.stage] = (stageDist[cls.stage] || 0) + 1;
234	  priorityDist[cls.priority] = (priorityDist[cls.priority] || 0) + 1;
235	  gradeDist[finalGrade] = (gradeDist[finalGrade] || 0) + 1;
236	});
237	
238	fs.writeFileSync('./data/s3_ai_judgments.json', JSON.stringify(results, null, 2));
239	
240	console.log('=== AI Classification v3 ===');
241	console.log('Total:', results.length, '| Grade corrections:', gradeCorrections);
242	console.log('Stages:', JSON.stringify(stageDist));
243	console.log('Stage count:', Object.keys(stageDist).length);
244	console.log('Priorities:', JSON.stringify(priorityDist));
245	console.log('Idle %:', (priorityDist.idle / results.length * 100).toFixed(1) + '%');
246	console.log('Grades:', JSON.stringify(gradeDist));
247	
248	const sc = Object.keys(stageDist).length;
249	const ip = priorityDist.idle / results.length * 100;
250	console.log('');
251	console.log(sc >= 6 ? 'PASS' : 'FAIL', 'stage count:', sc, '(need >=6)');
252	console.log(ip <= 60 ? 'PASS' : 'FAIL', 'idle:', ip.toFixed(1) + '% (need <=60%)');
253	
254	// Show now & soon counts
255	const nowList = results.filter(r => r.priority === 'now');
256	console.log('\n--- NOW (' + nowList.length + ') ---');
257	nowList.forEach(r => console.log('  ' + r.name + ' | ' + r.country + ' | ' + r.grade + ' | ' + r.stage + ' | ' + r.reason));
258	
259	// Check the 3 球在对方 customers
260	console.log('\n--- 球在对方 (to_us) ---');
261	const toUsS2 = s2.filter(c => c.direction === 'to_us');
262	toUsS2.forEach(c => {
263	  const r = results.find(x => x.cid === c.cid);
264	  console.log('  ' + r.name + ' | ' + r.country + ' | ' + r.grade + ' | ' + r.stage + ' | ' + r.priority);
265	});
